import json
import yaml
from typing import Any, Dict, List, Union
from datetime import datetime

def save_preferences(preferences: Dict[str, Any], filepath: str) -> None:
    """Save user preferences to a file in JSON format."""
    try:
        with open(filepath, 'w') as f:
            json.dump(preferences, f, indent=2, default=str)
    except Exception as e:
        raise ValueError(f"Failed to save preferences: {e}")

def load_preferences(filepath: str) -> Dict[str, Any]:
    """Load user preferences from a file with validation."""
    try:
        with open(filepath, 'r') as f:
            data = json.load(f)
        
        # Validate the structure
        validated_data = _validate_preferences(data)
        return validated_data
        
    except Exception as e:
        raise ValueError(f"Failed to load preferences: {e}")

def _validate_preferences(data: Any) -> Dict[str, Any]:
    """Validate and sanitize loaded preferences data."""
    if not isinstance(data, dict):
        raise ValueError("Preferences data must be a dictionary")
    
    validated = {}
    for key, value in data.items():
        if not isinstance(key, str):
            raise ValueError("Preference keys must be strings")
        
        validated[key] = _validate_value(value)
    
    return validated

def _validate_value(value: Any) -> Any:
    """Recursively validate and sanitize values."""
    if isinstance(value, (str, int, float, bool, type(None))):
        return value
    elif isinstance(value, list):
        return [_validate_value(item) for item in value]
    elif isinstance(value, dict):
        validated_dict = {}
        for k, v in value.items():
            if not isinstance(k, str):
                raise ValueError("Dictionary keys must be strings")
            validated_dict[k] = _validate_value(v)
        return validated_dict
    elif isinstance(value, (datetime, type)):
        # Convert datetime objects to string representation
        return str(value)
    else:
        # For custom objects, convert to string representation
        return str(value)